+/// Statistics time period selector.
+#[derive(Debug, Clone)]
+pub enum StatsPeriod {
+    Today,
+    Yesterday,
+    Last7Days,
+    Last30Days,
+    ThisMonth,
+    LastMonth,
+    Custom { from: DateTime<Utc>, to: DateTime<Utc> },
+}
+
+impl StatsPeriod {
+    fn to_range(&self) -> (DateTime<Utc>, DateTime<Utc>) {
+        match self {
+            Self::Today => {
+                let now = Utc::now();
+                let start = start_of_day(now.date_naive());
+                (start, now)
+            }
+            Self::Yesterday => {
+                let now = Utc::now();
+                let today = now.date_naive();
+                let start = start_of_day(today - Duration::days(1));
+                let end = start_of_day(today);
+                (start, end)
+            }
+            Self::Last7Days => {
+                let now = Utc::now();
+                (now - Duration::days(7), now)
+            }
+            Self::Last30Days => {
+                let now = Utc::now();
+                (now - Duration::days(30), now)
+            }
+            Self::ThisMonth => {
+                let now = Utc::now();
+                let today = now.date_naive();
+                let start = start_of_month(today);
+                (start, now)
+            }
+            Self::LastMonth => {
+                let now = Utc::now();
+                let today = now.date_naive();
+                let this_month = start_of_month(today);
+                let last_month = start_of_previous_month(today);
+                (last_month, this_month)
+            }
+            Self::Custom { from, to } => (from.clone(), to.clone()),
+        }
+    }
+}
